<?php
namespace Zclone\controllers; use Zclone\Core\Request; use Zclone\Core\Response; use Zclone\services\AuthService; final class AuthController { public function __construct(private AuthService $auth) {} public function loginForm(Request $r): void { Response::view('auth/login'); } public function registerForm(Request $r): void { Response::view('auth/register'); } public function login(Request $r): void { $this->auth->login((string)$r->input('email'),(string)$r->input('password')) ? Response::redirect('/dashboard') : Response::view('auth/login',['error'=>'Invalid credentials']); } public function register(Request $r): void { $this->auth->register((string)$r->input('email'),(string)$r->input('username'),(string)$r->input('password')); Response::redirect('/login'); } public function logout(Request $r): void { session_destroy(); Response::redirect('/'); } }
